+/**
+ * Email notification adapter — delivers notifications via email.
+ *
+ * This is a stub implementation that logs emails instead of sending them.
+ * Replace the send() method with a real email provider (e.g., SendGrid, SES)
+ * for production use. The interface contract remains the same.
+ */
+
+import type { NotificationPayload } from '../models/notification.js';
+import type { NotificationAdapter } from './notification.adapter.js';
+import { Logger } from '../utils/logger.js';
+
+export interface EmailConfig {
+  /** Sender email address */
+  from: string;
+  /** SMTP host (unused in stub) */
+  host?: string;
+  /** SMTP port (unused in stub) */
+  port?: number;
+}
+
+export class EmailAdapter implements NotificationAdapter {
+  readonly channel = 'email' as const;
+  private logger = new Logger('EmailAdapter');
+  private sentEmails: Array<{ to: string; from: string; subject: string; body: string }> = [];
+
+  constructor(private config: EmailConfig) {}
+
+  /**
+   * Send a notification via email.
+   * Stub implementation: logs the email and stores it in memory.
+   * @param payload - The notification to deliver
+   * @throws Error if recipient is not a valid email format
+   */
+  async send(payload: NotificationPayload): Promise<void> {
+    if (!payload.recipient.includes('@')) {
+      throw new Error(`Invalid email recipient: ${payload.recipient}`);
+    }
+
+    const email = {
+      to: payload.recipient,
+      from: this.config.from,
+      subject: payload.subject,
+      body: payload.body,
+    };
+
+    this.sentEmails.push(email);
+    this.logger.info(`Email sent to ${email.to}: ${email.subject}`);
+  }
+
+  /**
+   * Get all emails sent by this adapter (for testing).
+   */
+  getSentEmails(): Array<{ to: string; from: string; subject: string; body: string }> {
+    return [...this.sentEmails];
+  }
+
+  /**
+   * Clear sent email log (for testing).
+   */
+  clearSentEmails(): void {
+    this.sentEmails = [];
+  }
+}

