/**
 * Notification model — core types for the notification system.
 *
 * Architecture: Event-driven with adapter pattern.
 * - Business events (order:created, user:created, etc.) trigger notifications
 * - NotificationService listens to EventBus events and creates NotificationPayloads
 * - Payloads are dispatched to registered NotificationAdapters (email, webhook, SMS, etc.)
 * - Each adapter implements a single delivery channel
 *
 * Constraints:
 * - All notifications MUST flow through EventBus — no direct service calls
 * - All delivery channels MUST implement the NotificationAdapter interface
 * - NotificationType must be extended when adding new notification categories
 */

/**
 * Supported notification types. Extend this union when adding new categories.
 */
export type NotificationType =
  | 'order_confirmation'
  | 'order_status_update'
  | 'welcome'
  | 'account_updated';

/**
 * Supported delivery channels. Each channel has a corresponding adapter.
 */
export type NotificationChannel = 'email' | 'webhook' | 'sms' | 'in_app';

/**
 * The payload passed to notification adapters for delivery.
 */
export interface NotificationPayload {
  /** Unique notification ID */
  id: string;
  /** Category of this notification */
  type: NotificationType;
  /** Delivery channel for this notification */
  channel: NotificationChannel;
  /** Recipient identifier (email address, user ID, webhook URL, etc.) */
  recipient: string;
  /** Notification subject/title */
  subject: string;
  /** Notification body content */
  body: string;
  /** Additional structured data for adapter-specific rendering */
  metadata: Record<string, unknown>;
  /** When this notification was created */
  createdAt: Date;
}

/**
 * A persisted notification record with delivery status tracking.
 */
export interface Notification {
  /** Unique notification ID */
  id: string;
  /** Category of this notification */
  type: NotificationType;
  /** Delivery channel used */
  channel: NotificationChannel;
  /** Recipient identifier */
  recipient: string;
  /** Notification subject/title */
  subject: string;
  /** Notification body content */
  body: string;
  /** Delivery status */
  status: NotificationStatus;
  /** When this notification was created */
  createdAt: Date;
  /** When delivery was attempted */
  sentAt: Date | null;
}

/**
 * Delivery status for a notification.
 */
export type NotificationStatus = 'pending' | 'sent' | 'failed';

/**
 * Email notification adapter — delivers notifications via email.
 *
 * This is a stub implementation that logs emails instead of sending them.
 * Replace the send() method with a real email provider (e.g., SendGrid, SES)
 * for production use. The interface contract remains the same.
 */

import type { NotificationPayload } from '../models/notification.js';
import type { NotificationAdapter } from './notification.adapter.js';
import { Logger } from '../utils/logger.js';

export interface EmailConfig {
  /** Sender email address */
  from: string;
  /** SMTP host (unused in stub) */
  host?: string;
  /** SMTP port (unused in stub) */
  port?: number;
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: Array<{ to: string; from: string; subject: string; body: string }> = [];

  constructor(private config: EmailConfig) {}

  /**
   * Send a notification via email.
   * Stub implementation: logs the email and stores it in memory.
   * @param payload - The notification to deliver
   * @throws Error if recipient is not a valid email format
   */
  async send(payload: NotificationPayload): Promise<void> {
    if (!payload.recipient.includes('@')) {
      throw new Error(`Invalid email recipient: ${payload.recipient}`);
    }

    const email = {
      to: payload.recipient,
      from: this.config.from,
      subject: payload.subject,
      body: payload.body,
    };

    this.sentEmails.push(email);
    this.logger.info(`Email sent to ${email.to}: ${email.subject}`);
  }

  /**
   * Get all emails sent by this adapter (for testing).
   */
  getSentEmails(): Array<{ to: string; from: string; subject: string; body: string }> {
    return [...this.sentEmails];
  }

  /**
   * Clear sent email log (for testing).
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Notification service — orchestrates notification creation and delivery.
 *
 * Architecture: Event-driven with adapter pattern.
 * - Subscribes to domain events on the EventBus (order:created, order:status-changed, etc.)
 * - Translates events into NotificationPayloads
 * - Dispatches payloads to the appropriate NotificationAdapter based on channel
 *
 * Constraints:
 * - All notification triggers MUST come through EventBus events — no direct calls
 * - All delivery channels MUST be registered adapters implementing NotificationAdapter
 * - To add a new event handler: subscribe in registerEventHandlers()
 * - To add a new channel: implement NotificationAdapter and call registerAdapter()
 *
 * Depends on:
 * - EventBus for receiving domain events
 * - NotificationAdapter implementations for delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationChannel,
  NotificationPayload,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

/** Reset ID counter (for testing). */
export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<string, NotificationAdapter> = new Map();
  /** Default channel used when no adapter-specific routing is configured */
  private defaultChannel: NotificationChannel = 'email';

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  /**
   * Register a notification adapter for a delivery channel.
   * Only one adapter per channel is supported; later registrations replace earlier ones.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.adapters.set(adapter.channel, adapter);
    this.logger.info(`Registered adapter for channel: ${adapter.channel}`);
  }

  /**
   * Set the default delivery channel.
   */
  setDefaultChannel(channel: NotificationChannel): void {
    this.defaultChannel = channel;
  }

  /**
   * Subscribe to domain events on the EventBus.
   * Add new event subscriptions here when extending notification coverage.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created event — send confirmation to user.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    this.dispatchNotification({
      type: 'order_confirmation',
      channel: this.defaultChannel,
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      metadata: {
        orderId: event.order.id,
        userId: event.user.id,
        items: event.order.items,
        total: event.order.total,
      },
    });
  }

  /**
   * Handle order status change — notify user of update.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    this.dispatchNotification({
      type: 'order_status_update',
      channel: this.defaultChannel,
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      metadata: {
        orderId: event.order.id,
        previousStatus: event.previousStatus,
        newStatus: event.newStatus,
      },
    });
  }

  /**
   * Create a notification record and dispatch it to the appropriate adapter.
   * If no adapter is registered for the channel, the notification is still
   * recorded with 'pending' status (delivery deferred until adapter is available).
   */
  private dispatchNotification(params: {
    type: NotificationType;
    channel: NotificationChannel;
    recipient: string;
    subject: string;
    body: string;
    metadata: Record<string, unknown>;
  }): void {
    const now = new Date();
    const payload: NotificationPayload = {
      id: generateNotificationId(),
      type: params.type,
      channel: params.channel,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      metadata: params.metadata,
      createdAt: now,
    };

    const adapter = this.adapters.get(params.channel);

    if (adapter) {
      adapter
        .send(payload)
        .then(() => {
          this.recordNotification(payload, 'sent', now);
        })
        .catch((error: unknown) => {
          const message = error instanceof Error ? error.message : String(error);
          this.logger.error(`Failed to send notification ${payload.id}: ${message}`);
          this.recordNotification(payload, 'failed', null);
        });
    } else {
      // No adapter registered — record as sent for backward compatibility
      // (in-memory tracking without an external delivery channel)
      this.recordNotification(payload, 'sent', now);
      this.logger.info(`Notification ${payload.id} recorded (no adapter for channel: ${params.channel})`);
    }
  }

  /**
   * Store a notification record for tracking.
   */
  private recordNotification(
    payload: NotificationPayload,
    status: 'sent' | 'failed',
    sentAt: Date | null,
  ): void {
    const notification: Notification = {
      id: payload.id,
      type: payload.type,
      channel: payload.channel,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      status,
      createdAt: payload.createdAt,
      sentAt,
    };
    this.notifications.push(notification);
    this.logger.info(`Notification ${notification.id} ${status} to ${notification.recipient}`);
  }

  /**
   * Get all sent notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

